"use client";

/**
 * Kanban board with drag-and-drop — cold-start build on @gunjo/ui@0.0.1-alpha.2.
 *
 * DISCOVERY NOTES (treating @gunjo/ui as a black box):
 *
 *  - @gunjo/ui DOES ship a `KanbanTemplate` pattern (exported from the typed
 *    barrel) BUT it is a *static layout frame only*: it renders an optional
 *    sidebar + header + a horizontal flex strip for `children` (the columns).
 *    It provides NO drag-and-drop, NO column primitive, NO card primitive, and
 *    NO state. Its root className is also `w-[1280px] h-[720px] h-screen w-full`
 *    — the fixed `w-[1280px]`/`h-[720px]` are immediately overridden by
 *    `w-full`/`h-screen`, so it always wants full-viewport size. Inside a
 *    normal page that fights the surrounding layout, so I render the board
 *    layout directly with gunjo's layout tokens instead of KanbanTemplate.
 *  - There is NO Sortable / Draggable / Droppable / DnD primitive anywhere in
 *    the barrel. `SidebarItem` exposes raw HTML5 drag props for tree reordering,
 *    and `FileUploader` has drag-to-upload — neither is a board DnD engine.
 *  - So I brought my own DnD: @dnd-kit/core + @dnd-kit/sortable + utilities.
 *    The CARDS themselves are composed from gunjo: Card / CardContent /
 *    CardHeader / Badge / Avatar / AvatarFallback / Separator / Button.
 *  - `Card` is a plain forwardRef div that spreads all HTML attrs, so attaching
 *    dnd-kit's listeners/attributes/ref to it Just Works.
 *  - `Avatar` is "use client" and self-contains its own Radix Tooltip provider
 *    when given a `tooltip` prop, so no app-level TooltipProvider is required.
 */

import * as React from "react";
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  KeyboardSensor,
  useSensor,
  useSensors,
  closestCorners,
  type DragStartEvent,
  type DragOverEvent,
  type DragEndEvent,
} from "@dnd-kit/core";
import {
  SortableContext,
  useSortable,
  arrayMove,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

import {
  Card,
  CardContent,
  CardHeader,
  Badge,
  Avatar,
  AvatarFallback,
  Separator,
  Button,
  type BadgeProps,
} from "@gunjo/ui";

/* ---------------------------------------------------------------- model -- */

type ColumnId = "todo" | "in-progress" | "done";
type Priority = "low" | "medium" | "high";

interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: { name: string; initials: string };
}

const COLUMN_ORDER: ColumnId[] = ["todo", "in-progress", "done"];
const COLUMN_LABEL: Record<ColumnId, string> = {
  todo: "未着手",
  "in-progress": "対応中",
  done: "完了",
};

const PRIORITY_VARIANT: Record<Priority, NonNullable<BadgeProps["variant"]>> = {
  high: "destructive",
  medium: "default",
  low: "secondary",
};

const PRIORITY_LABEL: Record<Priority, string> = {
  high: "高",
  medium: "中",
  low: "低",
};

type BoardState = Record<ColumnId, Task[]>;

const INITIAL: BoardState = {
  todo: [
    { id: "t1", title: "オンボーディングの空状態を定義する", priority: "high", assignee: { name: "田中 愛子", initials: "AT" } },
    { id: "t2", title: "配色コントラストのトークンを監査する", priority: "medium", assignee: { name: "鈴木 蓮", initials: "SR" } },
    { id: "t3", title: "alpha.3 の変更履歴を草案する", priority: "low", assignee: { name: "森 千夏", initials: "MC" } },
  ],
  "in-progress": [
    { id: "t4", title: "/board にドラッグ＆ドロップを実装する", priority: "high", assignee: { name: "中村 大樹", initials: "ND" } },
    { id: "t5", title: "ツールチッププロバイダの回帰テスト", priority: "medium", assignee: { name: "田中 愛子", initials: "AT" } },
  ],
  done: [
    { id: "t6", title: "Card / Badge / Avatar のドキュメントを公開する", priority: "low", assignee: { name: "鈴木 蓮", initials: "SR" } },
    { id: "t7", title: "Tailwind v4 プリセットの配線", priority: "medium", assignee: { name: "中村 大樹", initials: "ND" } },
  ],
};

/* ----------------------------------------------------------- utilities -- */

/** Find which column a task id currently lives in. */
function columnOf(state: BoardState, id: string): ColumnId | undefined {
  if (id in COLUMN_LABEL) return id as ColumnId;
  return COLUMN_ORDER.find((c) => state[c].some((t) => t.id === id));
}

function findTask(state: BoardState, id: string): Task | undefined {
  for (const c of COLUMN_ORDER) {
    const t = state[c].find((x) => x.id === id);
    if (t) return t;
  }
  return undefined;
}

/* --------------------------------------------------------- card visual -- */

function TaskCardView({
  task,
  dragging = false,
  attributes,
  listeners,
  setNodeRef,
  style,
}: {
  task: Task;
  dragging?: boolean;
  attributes?: React.HTMLAttributes<HTMLDivElement>;
  listeners?: Record<string, (...args: unknown[]) => void>;
  setNodeRef?: (el: HTMLElement | null) => void;
  style?: React.CSSProperties;
}) {
  return (
    <Card
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...(listeners as React.HTMLAttributes<HTMLDivElement>)}
      className={[
        "cursor-grab touch-none select-none active:cursor-grabbing",
        dragging ? "opacity-40" : "shadow-sm hover:border-foreground/30",
      ].join(" ")}
    >
      <CardHeader className="flex-row items-center justify-between space-y-0 p-4 pb-2">
        <Badge variant={PRIORITY_VARIANT[task.priority]}>{PRIORITY_LABEL[task.priority]}</Badge>
        <Avatar
          className="h-7 w-7"
          tooltip={task.assignee.name}
          aria-label={`担当: ${task.assignee.name}`}
        >
          <AvatarFallback className="text-[11px]">
            {task.assignee.initials}
          </AvatarFallback>
        </Avatar>
      </CardHeader>
      <CardContent className="p-4 pt-0">
        <p className="text-sm font-medium leading-snug text-card-foreground">
          {task.title}
        </p>
      </CardContent>
    </Card>
  );
}

/** A card wired into dnd-kit's sortable. */
function SortableTaskCard({ task }: { task: Task }) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: task.id });

  return (
    <TaskCardView
      task={task}
      dragging={isDragging}
      setNodeRef={setNodeRef}
      attributes={attributes as React.HTMLAttributes<HTMLDivElement>}
      listeners={listeners as Record<string, (...args: unknown[]) => void>}
      style={{
        transform: CSS.Transform.toString(transform),
        transition,
      }}
    />
  );
}

/* ------------------------------------------------------------- column -- */

function Column({ id, tasks }: { id: ColumnId; tasks: Task[] }) {
  // The whole column is a sortable container; useSortable on the column id
  // lets cards be dropped into an EMPTY column too (id is registered as a
  // droppable target via SortableContext below).
  const { setNodeRef, isOver } = useSortable({
    id,
    data: { type: "column" },
  });

  return (
    <section className="flex w-72 shrink-0 flex-col rounded-lg border bg-muted/40">
      <header className="flex items-center justify-between gap-2 px-4 py-3">
        <h2 className="text-sm font-semibold text-foreground">
          {COLUMN_LABEL[id]}
        </h2>
        <Badge variant="outline" aria-label={`${tasks.length}件のタスク`}>
          {tasks.length}
        </Badge>
      </header>
      <Separator />
      <SortableContext items={tasks.map((t) => t.id)} strategy={verticalListSortingStrategy}>
        <div
          ref={setNodeRef}
          data-column={id}
          className={[
            "flex min-h-32 flex-1 flex-col gap-3 p-3 transition-colors",
            isOver ? "bg-primary/5" : "",
          ].join(" ")}
        >
          {tasks.map((t) => (
            <SortableTaskCard key={t.id} task={t} />
          ))}
          {tasks.length === 0 && (
            <p className="rounded-md border border-dashed px-3 py-6 text-center text-xs text-muted-foreground">
              ここにタスクをドロップ
            </p>
          )}
        </div>
      </SortableContext>
    </section>
  );
}

/* -------------------------------------------------------------- board -- */

export default function BoardPage() {
  const [board, setBoard] = React.useState<BoardState>(INITIAL);
  const [activeId, setActiveId] = React.useState<string | null>(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 4 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const activeTask = activeId ? findTask(board, activeId) : undefined;
  const total = COLUMN_ORDER.reduce((n, c) => n + board[c].length, 0);

  function handleDragStart(e: DragStartEvent) {
    setActiveId(String(e.active.id));
  }

  // Move the dragged card between columns live, as it hovers, so the counts
  // and layout update in real time.
  function handleDragOver(e: DragOverEvent) {
    const { active, over } = e;
    if (!over) return;
    const activeIdStr = String(active.id);
    const overIdStr = String(over.id);

    const from = columnOf(board, activeIdStr);
    const to = columnOf(board, overIdStr);
    if (!from || !to || from === to) return;

    setBoard((prev) => {
      const fromItems = [...prev[from]];
      const toItems = [...prev[to]];
      const movingIndex = fromItems.findIndex((t) => t.id === activeIdStr);
      if (movingIndex === -1) return prev;
      const [moving] = fromItems.splice(movingIndex, 1);

      // If dropping over a card, insert at that card's position; over a column,
      // append to the end.
      const overIndex = toItems.findIndex((t) => t.id === overIdStr);
      const insertAt = overIndex === -1 ? toItems.length : overIndex;
      toItems.splice(insertAt, 0, moving);

      return { ...prev, [from]: fromItems, [to]: toItems };
    });
  }

  // Reorder within the destination column on drop.
  function handleDragEnd(e: DragEndEvent) {
    const { active, over } = e;
    setActiveId(null);
    if (!over) return;
    const activeIdStr = String(active.id);
    const overIdStr = String(over.id);

    const col = columnOf(board, activeIdStr);
    if (!col) return;
    if (activeIdStr === overIdStr) return;

    setBoard((prev) => {
      const items = prev[col];
      const oldIndex = items.findIndex((t) => t.id === activeIdStr);
      const newIndex = items.findIndex((t) => t.id === overIdStr);
      if (oldIndex === -1 || newIndex === -1) return prev;
      return { ...prev, [col]: arrayMove(items, oldIndex, newIndex) };
    });
  }

  function reset() {
    setBoard(INITIAL);
  }

  return (
    <main className="mx-auto flex w-full max-w-6xl flex-1 flex-col gap-6 p-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-foreground">
            スプリントボード
          </h1>
          <p className="text-sm text-muted-foreground">
            カードを列の間でドラッグできます——全{total}件のタスク。{" "}
            <code className="rounded bg-muted px-1 py-0.5 text-xs">@gunjo/ui</code>{" "}
            ＋ dnd-kit で構築。
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={reset}>
          ボードをリセット
        </Button>
      </div>

      <DndContext
        sensors={sensors}
        collisionDetection={closestCorners}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragEnd={handleDragEnd}
        onDragCancel={() => setActiveId(null)}
      >
        <div className="flex flex-1 items-start gap-4 overflow-x-auto pb-2">
          {COLUMN_ORDER.map((c) => (
            <Column key={c} id={c} tasks={board[c]} />
          ))}
        </div>

        <DragOverlay>
          {activeTask ? <TaskCardView task={activeTask} /> : null}
        </DragOverlay>
      </DndContext>
    </main>
  );
}
